mapper.select:
SELECT t.taskId, t.stageId, s.projectId, t.taskTitle, t.taskDescription, TO_CHAR(t.taskStartDate, 'YYYY-MM-DD'), TO_CHAR(t.taskEndDate, 'YYYY-MM-DD'), t.taskStatus, t.taskcreator, TO_CHAR(t.taskCreatedDate, 'YYYY-MM-DD'), s.stgTitle, s.sequence, e1.NAME AS taskCreaterName, e2.NAME AS name FROM TASK t LEFT JOIN STAGE s ON t.stageId = s.stageId LEFT JOIN EMPLOYEE2 e1 ON t.taskcreator = e1.empId LEFT JOIN EMPTASK ep ON t.taskId = ep.taskId LEFT JOIN EMPLOYEE2 e2 ON ep.empId = e2.empId WHERE s.PROJECTID = #{projectId}
AND
ORDER BY s.sequence ASC, t.taskStartDate ASC
